SELECT AVG(average_frequency_per_month) AS avg_frequency_per_month
FROM frequency
WHERE required_1_to_5_times_per_day = 1;

SELECT task_id, average_frequency_per_month, last_updated
FROM frequency
WHERE required_1_to_5_times_per_day = 1;

SELECT gear_name
FROM safety_gear
WHERE last_inspection_date <= date('now', '-1 year');
